#include <iostream>
#include <algorithm>
using namespace std;
int main()
{
    string s;
    cin>>s;
    int ans=0,count=0;
    for(int i=0;i<s.size()-1;i++)
    {
        if(s[i]!='-')
        {
            count++;
            ans=ans+(s[i]-'0')*count;
        }
    }
    char a=s[s.size()-1];
    int yu=ans%11;
    if(yu==10)
    {
        if(a=='X')
        {
            cout<<"Right";
        }
        else
        {
            cout<<s.substr(0,s.size()-1)<<"X";
        }
    }
    else
    {
        if(a==yu+'0')  
        {
            cout<<"Right";
        }
        else
        {
            cout<<s.substr(0,s.size()-1)<<yu;
        }
    }
}
